import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"代理工具","description":"","frontmatter":{},"headers":[],"relativePath":"features/proxy.md","filePath":"features/proxy.md"}'),i={name:"features/proxy.md"};function o(s,a,d,n,h,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="代理工具" tabindex="-1">代理工具 <a class="header-anchor" href="#代理工具" aria-label="Permalink to &quot;代理工具&quot;">​</a></h1><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>代理工具基于 Mihomo 内核，提供完整的代理管理功能，支持一键启停、配置管理、系统代理设置。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="一键启停" tabindex="-1">一键启停 <a class="header-anchor" href="#一键启停" aria-label="Permalink to &quot;一键启停&quot;">​</a></h3><ul><li>点击「启动」按钮启动代理</li><li>点击「停止」按钮停止代理</li><li>状态指示灯实时显示运行状态（绿色=运行中，红色=已停止）</li></ul><h3 id="配置管理" tabindex="-1">配置管理 <a class="header-anchor" href="#配置管理" aria-label="Permalink to &quot;配置管理&quot;">​</a></h3><ul><li><strong>上传配置</strong> — 支持 <code>.yaml</code>/<code>.yml</code> 格式配置文件</li><li><strong>编辑配置</strong> — 内置文本编辑器，在线修改配置</li><li><strong>保存配置</strong> — 自动追加必要字段，保存后重启代理生效</li></ul><h3 id="系统代理" tabindex="-1">系统代理 <a class="header-anchor" href="#系统代理" aria-label="Permalink to &quot;系统代理&quot;">​</a></h3><ul><li>启动代理时自动设置 Windows 系统代理</li><li>停止代理时自动清除系统代理</li><li>支持 HTTP/SOCKS5 代理协议</li></ul><h2 id="端口说明" tabindex="-1">端口说明 <a class="header-anchor" href="#端口说明" aria-label="Permalink to &quot;端口说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>端口</th><th>用途</th></tr></thead><tbody><tr><td>7890</td><td>混合代理端口（HTTP/SOCKS5）</td></tr><tr><td>9097</td><td>REST API 端口</td></tr><tr><td>19090</td><td>Dashboard 面板端口</td></tr></tbody></table><h2 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h2><p>代理运行后，可通过浏览器访问 MetaCubeXD 面板：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127.0.0.1:19090/ui</span></span></code></pre></div><p>面板功能：</p><ul><li>节点管理</li><li>规则管理</li><li>连接监控</li><li>流量统计</li></ul><h2 id="内核信息" tabindex="-1">内核信息 <a class="header-anchor" href="#内核信息" aria-label="Permalink to &quot;内核信息&quot;">​</a></h2><ul><li><strong>Mihomo 版本</strong>: v1.19.11</li><li><strong>支持协议</strong>: VMess, VLESS, Trojan, Shadowsocks, Hysteria, TUIC, WireGuard 等</li><li><strong>配置格式</strong>: YAML</li></ul>',19)])])}const b=t(i,[["render",o]]);export{p as __pageData,b as default};
